#!/usr/bin/env bash
# Update the Homebrew tap with the default compiled-binary formula.
#
# The primary `ax-code` formula tracks the GitHub release assets produced by
# the tag-driven release workflow. The compatibility `ax-code-source` formula
# remains available for users who intentionally want the source+bun launcher.
set -euo pipefail

VERSION="${GITHUB_REF_NAME#v}"
TAG="v${VERSION}"
RELEASE_BASE="https://github.com/defai-digital/ax-code/releases/download/${TAG}"
SOURCE_REPO="${GITHUB_REPOSITORY:-defai-digital/ax-code}"
TAP_AUTH_TOKEN="${TAP_TOKEN:-${GH_TOKEN:-}}"

if [ -z "${TAP_AUTH_TOKEN}" ]; then
  echo "::error::TAP_TOKEN or GH_TOKEN is required to update the Homebrew tap"
  exit 1
fi

sha256_file() {
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "$1" | cut -d' ' -f1
  else
    shasum -a 256 "$1" | cut -d' ' -f1
  fi
}

download_asset() {
  local asset="$1"
  local dest="/tmp/${asset}"
  local attempts=0
  local max_attempts=30

  rm -f "${dest}"
  while ! gh release download "${TAG}" \
    --repo "${SOURCE_REPO}" \
    --pattern "${asset}" \
    --dir /tmp \
    --clobber >/dev/null 2>&1; do
    attempts=$((attempts + 1))
    if [ "$attempts" -ge "$max_attempts" ]; then
      echo "::error::release asset ${asset} not available from ${SOURCE_REPO}@${TAG} after ${max_attempts} attempts"
      exit 1
    fi
    sleep 5
  done
  if [ ! -f "${dest}" ]; then
    echo "::error::release asset download succeeded but ${dest} was not created"
    exit 1
  fi

  sha256_file "${dest}"
}

DARWIN_ARM64_ASSET="ax-code-darwin-arm64.zip"
LINUX_ARM64_ASSET="ax-code-linux-arm64.tar.gz"
LINUX_X64_ASSET="ax-code-linux-x64-baseline.tar.gz"

DARWIN_ARM64_SHA="$(download_asset "${DARWIN_ARM64_ASSET}")"
LINUX_ARM64_SHA="$(download_asset "${LINUX_ARM64_ASSET}")"
LINUX_X64_SHA="$(download_asset "${LINUX_X64_ASSET}")"

cat > /tmp/ax-code.rb << HEADER
# typed: false
# frozen_string_literal: true

# Auto-generated by release workflow — do not edit manually.
#
# Default compiled-binary formula for ax-code. The source+bun launcher remains
# available as ax-code-source for compatibility and diagnosis.
class AxCode < Formula
  desc "Sovereign AI coding agent — provider-agnostic, LSP-first"
  homepage "https://github.com/defai-digital/ax-code"
  version "${VERSION}"
  license "MIT"

  on_macos do
    depends_on arch: :arm64
    url "${RELEASE_BASE}/${DARWIN_ARM64_ASSET}"
    sha256 "${DARWIN_ARM64_SHA}"
  end

  on_linux do
    if Hardware::CPU.arm?
      url "${RELEASE_BASE}/${LINUX_ARM64_ASSET}"
      sha256 "${LINUX_ARM64_SHA}"
    else
      url "${RELEASE_BASE}/${LINUX_X64_ASSET}"
      sha256 "${LINUX_X64_SHA}"
    end
  end

  depends_on "ripgrep"

  def install
    bin.install "ax-code"
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/ax-code --version")
  end
end
HEADER

echo "Generated formula:"
cat /tmp/ax-code.rb

TAP_DIR="$(mktemp -d)"
trap 'rm -rf "${TAP_DIR}"' EXIT
GH_TOKEN="${TAP_AUTH_TOKEN}" gh auth setup-git
GH_TOKEN="${TAP_AUTH_TOKEN}" gh repo clone defai-digital/homebrew-ax-code "${TAP_DIR}" -- --depth 1
cp /tmp/ax-code.rb "${TAP_DIR}/ax-code.rb"
cd "${TAP_DIR}"
git config user.name "github-actions[bot]"
git config user.email "github-actions[bot]@users.noreply.github.com"
git add ax-code.rb
if ! git diff --cached --quiet; then
  git commit -m "Update ax-code to v${VERSION}"
  git push
  echo "Homebrew tap updated to v${VERSION}"
else
  echo "Formula unchanged, skipping push"
fi
